/* [REQ-001] [MISRA-Rule-8.13] 一阶低通滤波器模块，截止频率10Hz，采样率100Hz，DAL-B安全等级 */
#include "lowpass_filter_10hz.h"

/* [REQ-001] [MISRA-Rule-8.9] 静态内部状态变量，不暴露给外部 */
static float64_t s_y_prev = 0.0;           /* [REQ-001] [MISRA-Rule-10.1] 上一拍输出值，float64类型避免精度损失 */
static uint8_t s_consecutive_stuck_count = 0U; /* [REQ-001] [MISRA-Rule-10.1] 连续卡死计数，范围0-3 */
static bool s_fault_detected = false;      /* [REQ-001] [MISRA-Rule-10.1] 故障标志位 */

/* [REQ-001] [MISRA-Rule-10.3] 饱和转换函数：将float64安全转换为uint16_t，防止溢出 */
static uint16_t saturating_cast_to_uint16(float64_t value)
{
    /* [REQ-001] [MISRA-Rule-14.4] 使用if-else结构避免复杂条件表达式 */
    if (value > 65535.0)
    {
        return 65535U;
    }
    else if (value < 0.0)
    {
        return 0U;
    }
    else
    {
        /* [REQ-001] [MISRA-Rule-10.3] 显式类型转换，避免隐式转换 */
        return (uint16_t)(value + 0.5); /* 四舍五入 */
    }
}

/* [REQ-001] [MISRA-Rule-8.13] 模块初始化函数，重置内部状态 */
void lowpass_filter_10hz_init(void)
{
    /* [REQ-001] [MISRA-Rule-10.1] 使用显式类型初始化 */
    s_y_prev = 0.0;
    s_consecutive_stuck_count = 0U;
    s_fault_detected = false;
}

/* [REQ-001] [MISRA-Rule-15.7] 滤波器主处理函数，输入原始传感器数据，输出滤波后数据 */
uint16_t lowpass_filter_10hz(uint16_t raw_input, bool * const fault_detected)
{
    /* [REQ-001] [MISRA-Rule-10.1] 输入转换为float64进行计算 */
    float64_t x = (float64_t)raw_input;
    float64_t y_new;
    float64_t diff;
    uint16_t filtered_output;

    /* [REQ-001] [MISRA-Rule-10.1] 计算差值，用于卡死检测 */
    diff = x - s_y_prev;
    if (diff < 0.0)
    {
        diff = -diff; /* [REQ-001] [MISRA-Rule-14.4] 取绝对值 */
    }

    /* [REQ-001] [MISRA-Rule-15.7] 卡死检测逻辑 */
    if (diff > 500.0)
    {
        /* [REQ-001] [MISRA-Rule-10.1] 差值超过阈值，重置卡死计数 */
        s_consecutive_stuck_count = 0U;
    }
    else
    {
        /* [REQ-001] [MISRA-Rule-10.1] 差值未超过阈值，增加卡死计数 */
        s_consecutive_stuck_count = s_consecutive_stuck_count + 1U;
    }

    /* [REQ-001] [MISRA-Rule-15.7] 判断是否触发卡死故障 */
    if (s_consecutive_stuck_count >= 3U)
    {
        /* [REQ-001] [MISRA-Rule-10.1] 卡死故障：保持上一拍安全值 */
        y_new = s_y_prev;
        s_fault_detected = true;
    }
    else
    {
        /* [REQ-001] [MISRA-Rule-10.1] 正常滤波：y[n] = alpha * x[n] + (1 - alpha) * y[n-1] */
        /* [REQ-001] [MISRA-Rule-10.1] alpha = 2 * pi * 10.0 / 100.0 = 0.6283185307179586 */
        y_new = (0.6283185307179586 * x) + ((1.0 - 0.6283185307179586) * s_y_prev);
        s_fault_detected = false;
    }

    /* [REQ-001] [MISRA-Rule-10.3] 饱和转换为uint16_t输出 */
    filtered_output = saturating_cast_to_uint16(y_new);

    /* [REQ-001] [MISRA-Rule-10.1] 更新内部状态 */
    s_y_prev = y_new;

    /* [REQ-001] [MISRA-Rule-17.8] 通过指针参数输出故障标志 */
    if (fault_detected != NULL)
    {
        *fault_detected = s_fault_detected;
    }

    return filtered_output;
}

