#ifndef LOWPASS_FILTER_10HZ_H
#define LOWPASS_FILTER_10HZ_H

/* [REQ-001] [MISRA-Rule-21.1] 使用标准类型定义 */
#include <stdint.h>
#include <stdbool.h>
#include <float.h>

/* [REQ-001] [MISRA-Rule-8.13] 模块初始化函数 */
void lowpass_filter_10hz_init(void);

/* [REQ-001] [MISRA-Rule-15.7] 滤波器主处理函数 */
/* [REQ-001] [MISRA-Rule-17.8] 输入：raw_input - 原始传感器数据 */
/* [REQ-001] [MISRA-Rule-17.8] 输出：fault_detected - 故障标志指针 */
/* [REQ-001] [MISRA-Rule-17.8] 返回：滤波后数据 */
